/**
 * @summary Get a single saved listing draft
 */
export const getGetListingDraftUrl = (id: string) => {
  return `/api/listings/${id}`;
};

export const getListingDraft = async (
  id: string,
  options?: RequestInit,
): Promise<ListingDraft> => {
  return customFetch<ListingDraft>(getGetListingDraftUrl(id), {
    ...options,
    method: "GET",
  });
};

export const getGetListingDraftQueryKey = (id: string) => {
  return [`/api/listings/${id}`] as const;
};

export const getGetListingDraftQueryOptions = <
  TData = Awaited<ReturnType<typeof getListingDraft>>,
  TError = ErrorType<unknown>,
>(
  id: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getListingDraft>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetListingDraftQueryKey(id);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getListingDraft>>> = ({
    signal,
  }) => getListingDraft(id, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getListingDraft>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetListingDraftQueryResult = NonNullable<
  Awaited<ReturnType<typeof getListingDraft>>
>;
export type GetListingDraftQueryError = ErrorType<unknown>;

